package main

import (
	"fmt"
	"strconv"
	"strings"
)

func main() {
	var n int
	fmt.Scan(&n)
	seen := make(map[int]bool)
	var parts []string
	for i := 0; i < n; i++ {
		var x int
		fmt.Scan(&x)
		if !seen[x] {
			seen[x] = true
			parts = append(parts, strconv.Itoa(x))
		}
	}
	fmt.Println(strings.Join(parts, " "))
}
